protected void new()
{
    // This tells the controller what method it should execute as the service.
    super(classStr(PwcSLMInventTransSync), methodStr(PwcSLMInventTransSync, process), SysOperationExecutionMode::Synchronous);
}

public static PwcSLMInventTransSyncController construct()
{
    PwcSLMInventTransSyncController      controller;

    controller = new PwcSLMInventTransSyncController();

    controller.parmShowDialog(true);
    controller.parmShowProgressForm(false);

    return controller;
}

public static void main(Args _args)
{
    PwcSLMInventTransSyncController controller;

    controller = PwcSLMInventTransSyncController::construct();

    controller.startOperation();
}

protected ClassDescription defaultCaption()
{
    return "Transaction sync to SLM";
}
